public class DataTypesDemo {
    public static void main(String[] args) {
        // Integer types
        byte b = 127;           // max 127
        short s = 32767;
        int i = 2_147_483_647;  // underscore for readability
        long l = 9_223_372_036_854_775_807L; // L suffix mandatory

        // Real number types
        float f = 3.14f;        // f suffix mandatory
        double d = 3.14159265;  // default for decimals

        // Char and boolean
        char c = 'A';           // Unicode, 2 bytes
        boolean flag = true;

        // Widening (automatic)
        int x = 100;
        double y = x;           // int → double automatically

        // Narrowing (manual cast, data loss)
        double price = 99.99;
        int rounded = (int) price;  // 99 — decimal truncated!

        // var keyword
        var name = "Alice";     // inferred as String
        var count = 0;          // inferred as int
        System.out.println(count + ": " + name);
    }
}

public class OperatorsDemo {
    public static void main(String[] args) {
        // Arithmetic
        System.out.println(7 / 2);      // 3 (integer division)
        System.out.println(7.0 / 2);    // 3.5
        System.out.println(7 % 3);      // 1 (remainder)
        System.out.println(2 << 3);     // 16 (2 * 2^3)
        System.out.println(16 >> 2);    // 4  (16 / 2^2)

        // Comparison
        int a = 5, b = 10;
        System.out.println(a == b);     // false
        System.out.println(a != b);     // true
        System.out.println(a < b);      // true

        // Logical with short-circuit
        String s = null;
        // Safe — short-circuit prevents NPE
        if (s != null && s.length() > 0) {
            System.out.println("Not empty");
        }

        // Ternary
        int max = (a > b) ? a : b;  // 10

        // instanceof
        Object obj = "Hello";
        System.out.println(obj instanceof String); // true
    }
}

public class ControlDemo {
    public static void main(String[] args) {
        // Enhanced switch (Java 14+)
        int day = 3;
        String dayName = switch(day) {
            case 1 -> "Monday";
            case 2 -> "Tuesday";
            case 3 -> "Wednesday";
            default -> "Unknown";
        };
        System.out.println(dayName); // Wednesday

        // Labelled break
        outer:
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                if (i == 1 && j == 1) break outer; // exits both loops
                System.out.println(i + "," + j);
            }
        }

        // do-while (runs at least once)
        int choice;
        do {
            System.out.println("1.Start 2.Stop");
            choice = new java.util.Scanner(System.in).nextInt();
        } while (choice != 2);
    }
}

public class MethodsDemo {
    // Type-1: no params, no return
    void greet() {
        System.out.println("Hello!");
    }

    // Type-2: no params, with return
    int getYear() {
        return 2024;
    }

    // Type-3: params, no return
    void printSum(int a, int b) {
        System.out.println("Sum: " + (a + b));
    }

    // Type-4: params, with return
    double calculateArea(double radius) {
        return Math.PI * radius * radius;
    }

    // Method Overloading — same name, different params
    int add(int a, int b) { return a + b; }
    double add(double a, double b) { return a + b; }  // OK
    int add(int a, int b, int c) { return a + b + c; } // OK
    // double add(int a, int b) { return a+b; } // ERROR: same signature!

    // Pass-by-value demo
    void modify(int x) { x = 100; } // doesn't affect original
    void modify(int[] arr) { arr[0] = 100; } // DOES affect original!

    public static void main(String[] args) {
        MethodsDemo d = new MethodsDemo();
        // Autoboxing
        Integer i = 42;        // int → Integer (autoboxing)
        int j = i;             // Integer → int (unboxing)
        System.out.println(d.calculateArea(5.0));
    }
}

import java.util.Arrays;

public class ArraysDemo {
    public static void main(String[] args) {
        // 1D Array
        int[] nums = {5, 2, 8, 1, 9, 3};
        System.out.println(nums.length);        // 6
        System.out.println(nums[2]);            // 8

        // 2D Regular Array
        int[][] matrix = new int[3][4]; // 3 rows, 4 cols
        matrix[0][0] = 10;

        // 2D Jagged Array
        int[][] jagged = new int[3][];
        jagged[0] = new int[]{1, 2};
        jagged[1] = new int[]{3, 4, 5, 6};
        jagged[2] = new int[]{7};

        // For-each loop
        for (int n : nums) {
            System.out.print(n + " "); // 5 2 8 1 9 3
        }

        // Arrays utility methods
        Arrays.sort(nums);
        System.out.println(Arrays.toString(nums));  // [1,2,3,5,8,9]
        int idx = Arrays.binarySearch(nums, 8);     // 4 (after sort)
        int[] copy = Arrays.copyOf(nums, 3);        // [1,2,3]
        Arrays.fill(copy, 0);                       // [0,0,0]

        // Varargs
        System.out.println(sum(1, 2, 3, 4, 5));    // 15
    }

    static int sum(int... numbers) {  // varargs
        int total = 0;
        for (int n : numbers) total += n;
        return total;
    }
}

public class StringsDemo {
    public static void main(String[] args) {
        // Immutability and String pool
        String s1 = "Hello";
        String s2 = "Hello";          // same object in pool
        String s3 = new String("Hello"); // new object in heap
        System.out.println(s1 == s2);   // true (same pool object)
        System.out.println(s1 == s3);   // false (different objects)
        System.out.println(s1.equals(s3)); // true (same content)

        // Common String methods
        String str = "  Hello, World!  ";
        System.out.println(str.length());         // 17
        System.out.println(str.trim());           // "Hello, World!"
        System.out.println(str.toUpperCase());    // "  HELLO, WORLD!  "
        System.out.println(str.indexOf("World")); // 9
        System.out.println(str.substring(2, 7));  // "Hello"
        System.out.println(str.replace("World", "Java")); // replace
        String[] words = "a,b,c".split(",");      // ["a","b","c"]

        // StringBuilder (mutable, fast)
        StringBuilder sb = new StringBuilder();
        sb.append("Hello");
        sb.append(" World");
        sb.insert(5, ",");            // "Hello, World"
        sb.reverse();                 // "dlroW ,olleH"
        System.out.println(sb.toString());

        // Conversions
        int num = Integer.parseInt("42");    // String → int
        String s = String.valueOf(42);       // int → String
        double d = Double.parseDouble("3.14"); // String → double
    }
}

public class BankAccount {
    private String accountNo;   // private — encapsulated
    private double balance;
    private String owner;

    // Parameterized constructor
    public BankAccount(String accountNo, String owner) {
        this.accountNo = accountNo;  // this. resolves shadowing
        this.owner = owner;
        this.balance = 0.0;          // default balance
    }

    // Constructor chaining
    public BankAccount(String accountNo, String owner, double initialBalance) {
        this(accountNo, owner);      // calls 2-param constructor
        this.balance = initialBalance;
    }

    // Getter — read-only access to balance
    public double getBalance() { return balance; }
    public String getOwner()   { return owner; }

    // Setter with validation
    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Invalid amount");
        this.balance += amount;
    }

    public boolean withdraw(double amount) {
        if (amount > balance) return false; // insufficient funds
        balance -= amount;
        return true;
    }

    public static void main(String[] args) {
        BankAccount acc = new BankAccount("ACC001", "Alice");
        acc.deposit(5000);
        acc.withdraw(2000);
        System.out.println(acc.getBalance()); // 3000.0
        // acc.balance = 999999; // ERROR: private!
    }
}

public class Counter {
    // Static variable — shared by all objects
    private static int totalObjects = 0;
    private int objectId;

    // Static block — runs once when class is loaded
    static {
        System.out.println("Class loaded!");
        totalObjects = 0;
    }

    // Instance block — runs for every object before constructor
    {
        totalObjects++;
        objectId = totalObjects;
        System.out.println("Instance block: object " + objectId);
    }

    public Counter() {
        System.out.println("Constructor: object " + objectId);
    }

    public static int getTotalObjects() {
        return totalObjects; // static method → static variable OK
    }

    public static void main(String[] args) {
        Counter c1 = new Counter(); // Class loaded! → Instance block → Constructor
        Counter c2 = new Counter(); // Instance block → Constructor only
        System.out.println(Counter.getTotalObjects()); // 2
    }
}

// Singleton Pattern
class DatabaseConnection {
    private static DatabaseConnection instance; // single instance
    private DatabaseConnection() {}             // private constructor

    public static DatabaseConnection getInstance() {
        if (instance == null) instance = new DatabaseConnection();
        return instance;                         // always same object
    }
}

// Parent class
public class Animal {
    protected String name;
    protected String sound;

    public Animal(String name, String sound) {
        this.name = name;
        this.sound = sound;
    }

    public void makeSound() {
        System.out.println(name + " says " + sound);
    }

    public String toString() {
        return "Animal: " + name;
    }
}

// Child class inherits from Animal
public class Dog extends Animal {
    private String breed;

    public Dog(String name, String breed) {
        super(name, "Woof"); // calls Animal constructor
        this.breed = breed;
    }

    @Override  // annotation — compiler verifies this is valid override
    public void makeSound() {
        super.makeSound();  // calls parent method
        System.out.println(breed + " dog barking!");
    }

    public static void main(String[] args) {
        Dog d = new Dog("Rex", "German Shepherd");
        d.makeSound(); // Rex says Woof + German Shepherd dog barking!
        System.out.println(d); // calls toString() from Animal
    }
}

// Abstract class
abstract class Shape {
    String color;

    Shape(String color) { this.color = color; }

    abstract double area();         // must be overridden
    abstract double perimeter();    // must be overridden

    void display() {                // concrete method — inherited
        System.out.printf("%s %s: area=%.2f%n", color, getClass().getSimpleName(), area());
    }
}

class Circle extends Shape {
    double radius;
    Circle(String color, double radius) { super(color); this.radius = radius; }

    @Override double area()      { return Math.PI * radius * radius; }
    @Override double perimeter() { return 2 * Math.PI * radius; }
}

// Interface with lambda
@FunctionalInterface
interface Calculator {
    int calculate(int a, int b);
}

public class PolyDemo {
    public static void main(String[] args) {
        // Runtime polymorphism
        Shape s = new Circle("Red", 5.0); // Shape ref, Circle obj
        s.display(); // Red Circle: area=78.54

        // Lambda expressions
        Calculator add = (a, b) -> a + b;
        Calculator mul = (a, b) -> a * b;
        System.out.println(add.calculate(3, 4));  // 7
        System.out.println(mul.calculate(3, 4));  // 12
    }
}

// Composition — Engine cannot exist without Car
class Engine {
    String type;
    int horsepower;

    Engine(String type, int hp) { this.type = type; this.horsepower = hp; }
    void start() { System.out.println(type + " engine started"); }
}

class Car {
    private String model;
    private Engine engine; // Car HAS-A Engine (Composition)

    // Constructor Injection
    Car(String model, String engineType, int hp) {
        this.model = model;
        this.engine = new Engine(engineType, hp); // Car creates Engine
    }

    void drive() {
        engine.start();  // delegation
        System.out.println(model + " is moving");
    }
}

// Aggregation — Student can exist without University
