import java.io.*;

// Custom Exception
class InsufficientFundsException extends Exception {
    private double amount;
    InsufficientFundsException(double amount) {
        super("Insufficient funds: need " + amount + " more");
        this.amount = amount;
    }
    double getAmount() { return amount; }
}

public class ExceptionDemo {
    // throws declares checked exception
    static void withdraw(double balance, double amount)
            throws InsufficientFundsException {
        if (amount > balance) {
            throw new InsufficientFundsException(amount - balance);
        }
        System.out.println("Withdrawn: " + amount);
    }

    public static void main(String[] args) {
        // try-catch-finally
        try {
            withdraw(100, 150);          // throws exception
        } catch (InsufficientFundsException e) {
            System.out.println(e.getMessage());
            System.out.println("Need: " + e.getAmount());
        } finally {
            System.out.println("Always runs"); // cleanup code
        }

        // try-with-resources (auto-close)
        try (BufferedReader br = new BufferedReader(new FileReader("file.txt"))) {
            String line = br.readLine();
            System.out.println(line);
        } catch (IOException e) {
            System.out.println("File error: " + e.getMessage());
        } // br.close() called automatically!

        // Multi-catch (Java 7)
        try {
            int[] arr = new int[5];
            arr[10] = Integer.parseInt("abc");
        } catch (ArrayIndexOutOfBoundsException | NumberFormatException e) {
            System.out.println("Caught: " + e.getClass().getSimpleName());
        }
    }
}

// Implementing Runnable (preferred)
class PrintTask implements Runnable {
    private String message;
    private int count;

    PrintTask(String message, int count) {
        this.message = message;
        this.count = count;
    }

    @Override
    public void run() {
        for (int i = 0; i < count; i++) {
            System.out.println(Thread.currentThread().getName() + ": " + message);
            try { Thread.sleep(100); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        }
    }
}

// Race condition and synchronization
class BankAccount {
    private double balance = 1000;

    // synchronized prevents race condition
    public synchronized void deposit(double amount) {
        double temp = balance;
        temp += amount;
        balance = temp;
    }

    public synchronized double getBalance() { return balance; }
}

public class ThreadDemo {
    public static void main(String[] args) throws InterruptedException {
        Thread t1 = new Thread(new PrintTask("Hello", 5), "Thread-1");
        Thread t2 = new Thread(() -> System.out.println("Lambda thread"), "Thread-2");

        t1.start();
        t2.start();
        t1.join(); // main waits for t1 to finish
        t2.join();
        System.out.println("Both threads done");
    }
}

import java.util.*;

public class CollectionsDemo {
    public static void main(String[] args) {
        // ArrayList — dynamic array
        List<String> list = new ArrayList<>();
        list.add("Alice"); list.add("Bob"); list.add("Alice"); // duplicates allowed
        list.remove("Bob");
        System.out.println(list.get(0));   // Alice (O(1) access)

        // HashSet — no duplicates
        Set<Integer> set = new HashSet<>();
        set.add(3); set.add(1); set.add(2); set.add(1); // duplicate ignored
        System.out.println(set); // [1, 2, 3] (unordered)

        // HashMap
        Map<String, Integer> scores = new HashMap<>();
        scores.put("Alice", 95);
        scores.put("Bob", 87);
        scores.getOrDefault("Carol", 0); // 0 if not found

        // Iterating map
        for (Map.Entry<String, Integer> entry : scores.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }

        // Streams (Java 8+)
        list.stream()
            .filter(s -> s.startsWith("A"))
            .map(String::toUpperCase)
            .forEach(System.out::println); // ALICE

        // Generics
        List<Integer> nums = new ArrayList<>();
        nums.add(10); // only Integer allowed
        // nums.add("hello"); // compile error!
    }
}
